\[\begin{aligned}
\text{Total outcomes} &= \binom{52}{2} = 1326 \\
P(\text{no king}) &= \frac{\binom{48}{2}}{\binom{52}{2}} = \frac{1128}{1326} = \frac{188}{221} \\
